parameters.jsCode:
const courses = $input.all();

if (courses.length === 0) {
  return [{
    json: {
      catalog_text: '_No courses are currently available. Contact your LMS admin to add courses._',
      course_count: 0
    }
  }];
}

const lines = courses.map(item => {
  const c = item.json;
  const tag = c.is_onboarding ? ' _(onboarding)_' : '';
  const desc = c.description ? `\n  ${c.description}` : '';
  return `*${c.code}*${tag} — ${c.title} · ${c.module_count} module${c.module_count != 1 ? 's' : ''}${desc}`;
});

return [{
  json: {
    catalog_text: lines.join('\n\n'),
    course_count: courses.length
  }
}];

const payload = $json;
const courseCode = (payload.text || '').trim().toUpperCase();
if (!courseCode) {
  return [{ json: { ...payload, courseCode: '', error: 'no_code' } }];
}
return [{ json: { ...payload, courseCode } }];

