const crypto = require('crypto');
const raw = $input.first().json;
const rawBody = raw.rawBody || '';
const headers = raw.headers || {};
const timestamp = String(headers['x-slack-request-timestamp'] || '');
const slackSignature = String(headers['x-slack-signature'] || '');
const signingSecret = String($env.SLACK_SIGNING_SECRET || '');
const fiveMinutesAgo = Math.floor(Date.now() / 1000) - 300;
if (!timestamp || parseInt(timestamp, 10) < fiveMinutesAgo) {
  return [{ json: { valid: false, reason: 'timestamp_expired_or_missing', ...raw } }];
}
if (!signingSecret) {
  return [{ json: { valid: false, reason: 'signing_secret_not_configured', ...raw } }];
}
const baseString = `v0:${timestamp}:${rawBody}`;
const hmac = crypto.createHmac('sha256', signingSecret).update(baseString).digest('hex');
const computed = `v0=${hmac}`;
let valid = false;
try {
  const a = Buffer.from(computed, 'utf8');
  const b = Buffer.from(slackSignature, 'utf8');
  if (a.length === b.length) {
    valid = crypto.timingSafeEqual(a, b);
  }
} catch (e) {
  valid = false;
}
const body = raw.body || {};
return [{ json: { valid, response_url: body.response_url || '', user_id: body.user_id || '' } }];

const rows = $('Query DB Snapshot').all().map(i => i.json);
const counts = {};
rows.forEach(r => { counts[r.table_name] = r.row_count; });
const ts = new Date().toUTCString();
return [{
  json: {
    text: `*LMS Google Sheets Backup Complete* — ${ts}\n` +
      `• Progress records: ${counts.progress ?? 0}\n` +
      `• Enrollments: ${counts.enrolments ?? 0}\n` +
      `• Certificates: ${counts.certificates ?? 0}\n` +
      `• Total users: ${counts.users ?? 0} | Courses: ${counts.courses ?? 0} | Modules: ${counts.modules ?? 0}`
  }
}];

const root = $json.body ?? $json;
const payload = typeof root.payload === 'string' ? JSON.parse(root.payload) : (root.payload || root);
return [{ json: payload }];

